// /frontend/src/components/WeatherApp.jsx
import React, { useEffect, useMemo, useState } from "react";
import SearchSection from "./SearchSection";
import WeatherOverlay from "./WeatherOverlay";
import Hourly from "./Hourly";
import Forecast from "./Forecast";
import Radar from "./Radar";
import BottomBar from "./BottomBar";

// Safe getter so we don't crash on undefined paths
const get = (o, p, f = "") =>
  p.split(".").reduce((a, k) => (a && a[k] != null ? a[k] : null), o) ?? f;

/**
 * Expected OpenWeather One Call 3.0 shape:
 * {
 *   current: { temp, feels_like, humidity, wind_speed, weather:[{main, description, icon}], sunrise, sunset, dt },
 *   hourly:  [ { dt, temp, weather:[{icon}] }, ... ],
 *   daily:   [ { dt, temp:{min,max}, weather:[{description, icon}] }, ... ],
 *   timezone: "America/New_York",
 *   location: { name: "Atlanta, GA" } // optional, if you track it
 * }
 */
export default function WeatherApp({ data = {} }) {
  const [showSearch, setShowSearch] = useState(false);

  // Hide search when scrolling down
  useEffect(() => {
    let lastY = window.scrollY;
    const onScroll = () => {
      const y = window.scrollY;
      if (y > 64 && y > lastY) setShowSearch(false);
      lastY = y;
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // OpenWeather pieces
  const now = get(data, "current", {});
  const hourly = get(data, "hourly", []);
  const daily = get(data, "daily", []);
  const tz = get(data, "timezone", "local");

  // Day/night for overlay
  const overlay = useMemo(() => {
    const main = (get(now, "weather[0].main", "") || "").toLowerCase();
    const t = get(now, "dt", null);
    const sunrise = get(now, "sunrise", 0);
    const sunset = get(now, "sunset", 24 * 3600);
    const isNight = t ? t < sunrise || t > sunset : false;
    return { cond: main, isNight };
  }, [now]);

  return (
    <div className="relative min-h-screen flex flex-col bg-white dark:bg-black text-white">
      {/* Weather background overlays */}
      <WeatherOverlay condition={overlay.cond} night={overlay.isNight} />

      {/* Sticky search (collapsible) */}
      <div className="sticky top-0 z-30 px-4 pt-3">
        <SearchSection
          value={get(data, "location.name", "")}
          open={showSearch}
          onToggle={(v) => setShowSearch(typeof v === "boolean" ? v : (s) => !s)}
          onSelected={() => setShowSearch(false)}
        />
      </div>

      {/* Main content */}
      <main className="flex-1 container mx-auto px-4 max-w-3xl">
        {/* Weather Now */}
        <section className="mt-6 mb-4 rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-4 text-center">
          <div className="text-4xl font-semibold">
            {Math.round(get(now, "temp", 0))}°
          </div>
          <div className="opacity-80 capitalize">
            {get(now, "weather[0].description", "—")}
          </div>
          <div className="text-sm opacity-70 mt-1">
            Feels {Math.round(get(now, "feels_like", 0))}° • Hum {Math.round(get(now, "humidity", 0))}% • Wind {Math.round(get(now, "wind_speed", 0))} {get(data,"units","imperial")==="imperial"?"mph":"m/s"}
          </div>
        </section>

        {/* Hourly (horizontal scroll + dots on mobile) */}
        <section className="mb-6">
          <Hourly hourly={hourly} timezone={tz} />
        </section>

        {/* Forecast (OW daily array; swipe on mobile, grid on desktop) */}
        <section className="mb-8">
          <Forecast daily={daily} />
        </section>

        {/* Radar (fast, latest frame by default) */}
        <section className="mb-24">
          <Radar />
        </section>
      </main>

      {/* Bottom bar */}
      <BottomBar />
    </div>
  );
}
